# Exemple d'utilisation de sockets TCP

créer un serveur TCP
server_tcp() {
  socket() { 
    listen(8080);
  }
}
sender_tcp() {
  socket() { 
    connect('127.0.0.1:8080');
  }
}
sample: server_tcp();
sample: sender_tcp();
créer un client TCP
client_tcp() {
  socket() { 
    connect('127.0.0.1:8080');
  }
}
sample: client_tcp();
